      const sn = q.state_detail?.name;
      return sn === 'To-Do' || sn === 'In Progress';
    });

    if (actionable.length === 0) {
      return [{ json: {
        response_type: 'info',
        message: '\u2139\uFE0F No quests available to complete. All quests are already done or canceled.',
        data: null, suggestions: ['Try /today to view your quest board'], awaiting_input: false
      }}];
    }

