const formatDuration = (min) => {
  if (min >= 60) { const h = Math.floor(min / 60); const m = min % 60; return m > 0 ? `${h}h${m}min` : `${h}h`; }
  return `${min}min`;
};

const params = $input.first().json.params || {};

try {
  const name = params.name;
  const durationStr = params.duration;

  if (!name || !durationStr) {
    return [{ json: {
      response_type: 'error',
      message: '\u274C [INVALID_INPUT] Usage: /add {name} {duration} (e.g., /add Code Review 1h). Please check input format and try again.',
      data: { error_code: 'INVALID_INPUT' },
      suggestions: ['Example: /add Code Review 1h', 'Example: /add Bug Fix 30min'],
      awaiting_input: false
    }}];
  }

  // Parse duration string (e.g., '1h', '30min', '1h30min', '90min')
  let durationMin = 0;
  const hMatch = durationStr.match(/(\d+)h/);
  const mMatch = durationStr.match(/(\d+)m(?:in)?/);
  if (hMatch) durationMin += parseInt(hMatch[1]) * 60;
  if (mMatch) durationMin += parseInt(mMatch[1]);
  if (durationMin === 0) {
    // Try plain number as minutes
    const plain = parseInt(durationStr);
    if (!isNaN(plain) && plain > 0) durationMin = plain;
  }

  if (durationMin <= 0) {
    return [{ json: {
      response_type: 'error',
      message: `\u274C [INVALID_INPUT] Invalid duration: '${durationStr}'. Use formats like 1h, 30min, or 1h30min. Please check input format and try again.`,
