  // Build pulse-meta for the manually added quest (manual type with all schema fields)
  const meta = {
    schema_version: 1,
    routine_type: 'manual',
    routine_days: [new Date().toLocaleDateString('en-US', { timeZone: tz, weekday: 'short' }).toLowerCase().slice(0, 3)],
    routine_time: nowStr,
