  };

  const descriptionHtml = `<pre><code class="language-pulse-meta">${JSON.stringify(meta, null, 2)}</code></pre>`;

  const projId = config.daily_quest_project_id;

  if (DRY_RUN) {
    console.log(`[DRY_RUN] Would create manual quest: "${name}" (${formatDuration(durationMin)})`);
  } else {
    await withRetry(
      () => apiPost(`/projects/${projId}/issues/`, {
        name,
        description_html: descriptionHtml,
        priority,
        state: config.state_todo,
        target_date: todayStr,
        start_date: todayStr
      }),
      'Create manual quest'
    );
  }

  const dryTag = DRY_RUN ? ' [DRY_RUN]' : '';
  return [{ json: {
    response_type: 'confirmation',
    message: `\u2705${dryTag} Quest added: "${name}" (${formatDuration(durationMin)})`,
