  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [W2-ADD] [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

// ===========================================
// /brief — Milestone Briefing
// ===========================================
// /brief: Top 5 milestones sorted by D-Day (closest deadline first)
// /brief all: All milestones grouped by project

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) {
        const isTimeout = e.code === 'ETIMEDOUT' || e.code === 'ECONNABORTED' || e.message?.includes('timeout');
        const errorCode = isTimeout ? 'PLANE_API_TIMEOUT' : 'PLANE_API_ERROR';
        const err = new Error(`[${errorCode}] ${ctx}: ${e.message}`);
        err.errorCode = errorCode;
        throw err;
      }
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const target = $input.first().json.target;
const showAll = target === 'all';

try {
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });

  // Fetch all projects
  const projectsRes = await withRetry(() => apiGet('/projects/'), 'List projects');
  const projects = projectsRes.results || projectsRes || [];

  const allMilestones = [];

  for (const project of projects) {
    // Fetch modules (milestones) for each project
    const modulesRes = await withRetry(
      () => apiGet(`/projects/${project.id}/modules/?per_page=100`),
      `List modules for ${project.name}`
    );
    const modules = modulesRes.results || modulesRes || [];

    for (const mod of modules) {
      if (!mod.target_date) continue;

      // Calculate D-Day
      const targetMs = new Date(mod.target_date + 'T00:00:00').getTime();
      const todayMs = new Date(todayStr + 'T00:00:00').getTime();
      const dDays = Math.ceil((targetMs - todayMs) / (24 * 60 * 60 * 1000));

      // Fetch module issues for progress calculation
      let progress = 0;
      try {
        const issuesRes = await withRetry(
          () => apiGet(`/projects/${project.id}/modules/${mod.id}/module-issues/?per_page=100&expand=state`),
          `Module issues for ${mod.name}`
        );
        const issues = issuesRes.results || issuesRes || [];
        const total = issues.length;
        if (total > 0) {
          const completed = issues.filter(i => {
            const issue = i.issue_detail || i;
            const stateName = issue.state_detail?.name || issue.state_name || '';
            return stateName === 'Done' || stateName === 'Canceled';
          }).length;
          progress = Math.round((completed / total) * 100);
        }
      } catch (e) {
        console.log(`[WARN] Could not fetch issues for module ${mod.name}: ${e.message}`);
      }

      allMilestones.push({
        project_name: project.name,
        milestone_name: mod.name,
        progress,
        d_days: dDays,
        target_date: mod.target_date,
        status: mod.status || 'unknown',
      });
    }
  }

  // Sort by D-Day (closest first)
  allMilestones.sort((a, b) => a.d_days - b.d_days);

  if (allMilestones.length === 0) {
    return [{ json: {
      response_type: 'info',
      message: '\u2139\uFE0F No milestones with due dates found across your projects.',
      data: null,
      suggestions: ['Create milestones (modules) in Plane.so with target dates'],
      awaiting_input: false
    }}];
  }

  let message = '';

  if (showAll) {
    // Group by project
    const grouped = {};
    for (const m of allMilestones) {
      if (!grouped[m.project_name]) grouped[m.project_name] = [];
      grouped[m.project_name].push(m);
    }

    message = '\uD83C\uDFAF **All Milestones**\n';
    for (const [projName, milestones] of Object.entries(grouped)) {
      message += `\n**${projName}**\n`;
      for (const m of milestones) {
        const dLabel = m.d_days >= 0 ? `D-${m.d_days}` : `D+${Math.abs(m.d_days)} (overdue)`;
        message += `  \uD83C\uDFAF ${m.milestone_name}: ${m.progress}% (${dLabel})\n`;
      }
    }
  } else {
    // Top 5
    const top5 = allMilestones.slice(0, 5);
    message = '\uD83C\uDFAF **Top 5 Milestones**\n\n';
    for (const m of top5) {
      const dLabel = m.d_days >= 0 ? `D-${m.d_days}` : `D+${Math.abs(m.d_days)} (overdue)`;
      message += `\uD83C\uDFAF ${m.project_name} \u2014 ${m.milestone_name}: ${m.progress}% (${dLabel})\n`;
    }
  }

  return [{ json: {
    response_type: 'info',
    message,
    data: { milestones: showAll ? allMilestones : allMilestones.slice(0, 5), total: allMilestones.length },
    suggestions: showAll ? [] : ['Use /brief all to see all milestones'],
    awaiting_input: false
  }}];
